 */
class Admin_Model_ProductSimiliar extends Admin_Model_Base_ProductSimiliar {

    public function save(Doctrine_Connection $conn = null) {
        parent::save($conn);
        Admin_Model_Product::updateProductDateTime($this->Product_ID);
    }

    /**
     * @param int $productID
     * @param ModelEshop|null $eshop
     * @return array
     * @throws Doctrine_Query_Exception
     */
    public static function getProductSimiliars(int $productID, ?ModelEshop $eshop = null): array {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_ProductSimiliar object');
        $query->addSelect('object.*, productSimiliar.*, productEshops.*, vat.*, productSimiliarEshops.*, productSimiliarLangs.*, productImages.*, file.*');
        //$query->addSelect('productSimiliarLangs.Name as ProductName, productSimiliarLangs.slug as slug');
        $query->addSelect('GROUP_CONCAT(categories.Category_ID SEPARATOR ",") as CategoryIDs');
        $query->leftJoin('object.productSimiliar productSimiliar');
        $query->innerJoin("productSimiliar.productEshops productSimiliarEshops WITH productSimiliarEshops.Active = 1 AND productSimiliarEshops.Eshop_ID = ?", $eshop->ID);
        $query->innerJoin("productSimiliar.productLangs productSimiliarLangs WITH productSimiliarLangs.Language_ID = ?", $eshop->Language_ID);
        $query->leftJoin('productSimiliar.productImages productImages');
        $query->leftJoin('productSimiliarEshops.vat vat');
        $query->leftJoin('productImages.file file');
        $query->leftJoin('productSimiliar.categories categories');
        $query->where('object.Product_ID = ?', $productID);
        $query->addGroupBy('object.ID');
        $query->addGroupBy('productImages.ID');
        $query->addOrderBy('productImages.Main DESC');
        $query->addOrderBy('RAND() ASC');
        $query->limit(4);
        $productSimiliars = $query->execute()->toArray();

        foreach ( $productSimiliars as &$productSimiliar ) {
            $productSimiliar['productSimiliar']['CategoryIDs'] = $productSimiliar['CategoryIDs'];
            $productPrice = new ProductPrice($productSimiliar['productSimiliar'], UserSettings::getInstance()->getValue('Discount'), UserSettings::getInstance()->getGroupDiscounts());
            $productSimiliar['productSimiliar'] = $productPrice->getProduct();
            $productSimiliar['productSimiliar']['slug'] = $productSimiliar['productSimiliar']['productLangs'][0]['slug'];
            $productSimiliar['productSimiliar']['ProductName'] = $productSimiliar['productSimiliar']['productLangs'][0]['Name'];
            $productSimiliar['productSimiliar']['Perex'] = $productSimiliar['productSimiliar']['productLangs'][0]['Perex'];
        }

        return $productSimiliars;
    }
}